INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-77f8735d-moex-00080', 'retired-77f8735d', 'retired-77f8735d-moex-112-13504c0c', 'sub-retired-77f8735d-01', NULL, 'single_choice', '「李漁說南方人吃切麵，把油鹽醬醋等作料，都下到麵湯裡，他對這種吃麵的辦法 期期以為不可，『湯有味而麵無味，是人所重者不在麵而在湯，與未嘗食麵等也。 予則不然，以調和諸物，盡歸於麵，麵具五味而湯獨清，如此方是食麵，非飲湯也。』 李漁自製『五香麵』，所謂的『五香』是醬、醋、椒末、芝麻屑，另加上焯筍或煮 蕈煮蝦的高湯；椒末、芝麻屑拌入麵裡，醬、醋、高湯作為和麵之水，拌勻，揉薄， 切細，如此一來美味盡在麵條之中。」 根據上文，符合李漁製麵的態度是：', '["煮湯麵時的調味越多樣越好", "油鹽醬醋的比例可隨性任意", "湯麵的關鍵在高湯，需精燉熬湯", "作麵時需調和醬料高湯和入麵中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00081', 'retired-77f8735d', 'retired-77f8735d-moex-112-13504c0c', 'sub-retired-77f8735d-01', NULL, 'single_choice', '甲若接受乙所提出的條件，則必須移居高雄；而甲若移居高雄，則不能留在臺中。 甲若接受丙所提出的條件，則必須留在臺中。甲必須接受乙或丙所提出的條件。因 此，甲必須移居高雄或留在臺中。 根據上文，下列選項何者正確？', '["甲必須選擇乙方所提出的條件，選擇移居高雄或留居臺中", "甲必須選擇丙方所提出的條件，選擇移居高雄或留居臺中", "甲必須只能接受乙或丙的條件，選擇移居高雄或留居臺中", "甲可以不接受乙和丙的條件，既不移居高雄也不移居臺中"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00082', 'retired-77f8735d', 'retired-77f8735d-moex-112-13504c0c', 'sub-retired-77f8735d-01', NULL, 'single_choice', '「高雄百貨業鉅子吳耀庭（1926年生）曾自述他十七歲那年，月薪從十七元跳到四 十元，於是身懷『巨款』，很神氣走進吉井百貨公司三樓，要幫母親買禮物。他問 女店員，『這面鏡子要多少錢？』女店員打量他一番，然後冷笑一聲『哼』！這聲 『哼』深深刺傷吳耀庭，他發願要在高雄創建一家超棒的百貨公司。戰後聞名南臺 灣的大新百貨公司，因而被『吉井』店員的惡劣態度刺激誕生。」 根據上文，下列選項最適合形容吳耀庭的是：', '["寶劍鋒從磨礪出，梅花香自苦寒來", "天生我材必有用，千金散盡還復來", "嘗將冷眼觀螃蟹，看你橫行到幾時", "翻手作雲覆手雨，紛紛輕薄何須數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00083', 'retired-77f8735d', 'retired-77f8735d-moex-112-13504c0c', 'sub-retired-77f8735d-01', NULL, 'single_choice', '「那天我們翻過雞籠山，居高臨下看見遠方的地平線，此時正冒出濃濃白煙，是美 國飛機剛轟炸過的基隆港。二戰已將近尾聲，從大人談話裡可聽出日軍正在節節敗 退。報紙上一再出現『決戰』字眼，他們面容竟絲毫不見憂心，不明白當了日本國 民五十年的臺灣人在心裡將自己擺在那一邊？回來以後，我好幾次夢見海上滿天都 是飛機，只慢慢移動甚至停留在海面，不時引發陣陣煙火……。又聽說有架美國 飛機落在山區，搜索隊回來時掏出好大的手錶，指針還運轉著，阿公看了有些傷感， 說：『美國手錶走的是美國時間，此時美國的家人還在等著他回去。』天未亮，隱 約聽到有女人哭泣的聲音，近午時聽說是收到未婚夫從遭攻擊的艦上，輾轉送出準 備好『全沒』的訣別書。」 下列敘述何者最接近主旨？', '["作者以孩童視角觀察戰爭中交迭的勝負", "作者疑惑大人對於日本政府的曖昧態度", "作者的家人對美軍相對期待並抱持同情", "作者的戰爭記憶中隱含了跨國族的創傷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00084', 'retired-77f8735d', 'retired-77f8735d-moex-112-13504c0c', 'sub-retired-77f8735d-01', NULL, 'single_choice', '「高音的條件，是要有寬厚充足的氣力，讓聲音上去，有飽滿的氣力來襯托，才不 會高而危薄，終不能長久。」 下列選項，何者最切合文中所表達的旨趣？', '["為高必因丘陵，為下必因川澤", "無為其所不為，無欲其所不欲", "水之積也不厚，則其負大舟也無力", "致廣大而盡精微，極高明而道中庸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00085', 'retired-77f8735d', 'retired-77f8735d-moex-112-13504c0c', 'sub-retired-77f8735d-01', NULL, 'single_choice', '「日本著名導演黑澤明的自傳用了一個奇怪的書名：《蝦蟆的油》。它來自日本的 一則民間傳說：有位醫生抓到一隻醜陋的蝦蟆，牠長有四隻前腳、六隻後腳。醫生 將蝦蟆裝進一個玻璃箱內，蝦蟆從鏡面的玻璃中，第一次看到自己醜陋的形象，嚇 得擠出一身油來。醫生收取這些油，用來治療病人的燒燙割傷，據說具有奇效。」 根據上文，下列何者最符合黑澤明傳記的命名旨趣？', '["作者自覺一生失敗難堪，猶如醜陋的蝦蟆，自慚形穢", "人世的險惡如醜陋的蝦蟆，令人驚駭莫名，細思極恐", "作者反思醜陋難堪的過往，透過書寫傳記以療傷止痛", "作者揭示自身難堪的經歷，盼能醫治讀者心靈的傷痛"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00086', 'retired-77f8735d', 'retired-77f8735d-moex-112-13504c0c', 'sub-retired-77f8735d-01', NULL, 'single_choice', '「紐曼認為大學是一個提供博雅教育，培育紳士的地方（雖然他也認為大學可以訓 練職業人才），他以為大學之目的在『傳授』學問而不在『發展』知識。他說：『如 果大學的目的在科學的與哲學的發明，那麼，我看不出為什麼大學應該有學生。』 紐曼之書為論大學之經典。他心中大學所應培育之紳士乃指通達而有修養與識見之 文化人。」 根據上文，最符合文中旨意的選項是：', '["大學最重要的目的在培育有創見的學者", "大學應以學生為重，提供優良博雅教育", "大學應該積極作為訓練職業人才的地方", "科學的與哲學的發明，是大學重要目的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00087', 'retired-77f8735d', 'retired-77f8735d-moex-112-13504c0c', 'sub-retired-77f8735d-01', NULL, 'single_choice', '「2006年3月，設計博物館與BBC舉辦大眾票選，尋找英國最愛的設計符碼，紅 色電話亭名列前茅。儘管如今它幾乎失去了原有的功能，它的歷史、設計與過往日 常生活中的地位，也使它優雅地成為英國的國家象徵，也是公共性的體現。或許在 不久的將來，紅色電話亭也會跟文書軟體上代表儲存的磁碟片圖示一樣，晦澀而遙 遠。儘管原有的功能已成歷史，然而在符碼再次轉化與詮釋的過程中，似乎還是可 以發揮新意，這點也很英國。」 根據上文，「這點也很英國」的看法，下列選項何者正確？', '["希望能在保留傳統的同時，也發展出新的創見和意涵", "偏愛晦澀且遙遠的事物，因此希望保留古老的紅色電話亭", "強調優雅與日常，而紅色電話亭的設計正是符合這樣的要求", "重視傳統與科技的平衡，希望將傳統的文化以新興的科技保存下來"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00088', 'retired-77f8735d', 'retired-77f8735d-moex-112-3d2b73b6', 'sub-retired-77f8735d-02', NULL, 'single_choice', '1 考 試 別：一般警察人員考試、鐵路人員考試、退除役軍人轉任公務人員考試 類科組別：各類別、各類科', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00089', 'retired-77f8735d', 'retired-77f8735d-moex-112-3d2b73b6', 'sub-retired-77f8735d-02', NULL, 'single_choice', '有關法治國原則，下列敘述何者正確？', '["大法官迄今尚未承認法治國原則為我國憲法基本原則", "地方政府限制人民之自由權利，若屬地方自治事項，即無法治國原則之適用", "法治國原則要求，立法者制定法律時，不得在法律中使用不確定法律概念", "司法機關行使司法權，亦受法治國原則拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL)
